 1	import type { FC } from 'react';
 2	import { isPlanEditable } from 'src/plans/details/components/PlanStatus/utils/utils';
 3	
 4	import type { V1beta1Plan } from '@kubev2v/types';
 5	import { Button, ButtonVariant, HelperText, HelperTextItem } from '@patternfly/react-core';
 6	import { PencilAltIcon } from '@patternfly/react-icons';
 7	import { getName, getNamespace } from '@utils/crds/common/selectors';
 8	import { useForkliftTranslation } from '@utils/i18n';
 9	
10	import { canDeleteAndPatchPlanMaps, hasSomeCompleteRunningVMs } from './utils/utils';
11	
12	import './PlanMappingEditButton.scss';
13	
14	type PlanMappingEditButtonProps = {
15	  plan: V1beta1Plan;
16	  onEdit: () => void;
17	};
18	
19	const PlanMappingEditButton: FC<PlanMappingEditButtonProps> = ({ onEdit, plan }) => {
20	  const { t } = useForkliftTranslation();
21	
22	  if (!canDeleteAndPatchPlanMaps({ name: getName(plan), namespace: getNamespace(plan) })) {
23	    return null;
24	  }
25	
26	  const disableEditMappings = hasSomeCompleteRunningVMs(plan) || !isPlanEditable(plan);
27	  return (
28	    <>
29	      <Button
30	        variant={ButtonVariant.secondary}
31	        icon={<PencilAltIcon />}
32	        onClick={onEdit}
33	        isDisabled={disableEditMappings}
34	        className="forklift-plan-mapping-edit-button"
35	        data-testid="edit-mappings-button"
36	      >
37	        {t('Edit mappings')}
38	      </Button>
39	      {disableEditMappings && (
40	        <HelperText className="forklift-plan-mapping-edit-button__helper-text">
41	          <HelperTextItem variant="indeterminate">
42	            {t(
43	              'The edit mappings button is disabled if the plan started running and at least one virtual machine was migrated successfully or when the plan status does not enable editing.',
44	            )}
45	          </HelperTextItem>
46	        </HelperText>
47	      )}
48	    </>
49	  );
50	};
51	
52	export default PlanMappingEditButton;

